const input = $input.first().json;
const body = input.body ?? input;
const detectedPath = body.raw_path || body.path || body.filePath || body.filename || 'raw/inbox/example.md';
const normalized = {
  raw_path: detectedPath,
  trigger_source: body.path || body.filePath || body.filename ? 'local-file-trigger' : 'manual',
  captured_at: body.captured_at || new Date().toISOString()
};
return [{ json: normalized }];

const payload = $input.first().json;
return [{
  json: {
    payload,
    payload_b64: Buffer.from(JSON.stringify(payload), 'utf8').toString('base64')
  }
}];

const stdout = $input.first().json.stdout ?? '';
if (!stdout.trim()) {
  throw new Error('ingest-source.ts returned empty stdout');
}
const source_payload = JSON.parse(stdout);
return [{
  json: {
    source_payload,
    payload_b64: Buffer.from(JSON.stringify(source_payload), 'utf8').toString('base64')
  }
}];

const stdout = $input.first().json.stdout ?? '';
if (!stdout.trim()) {
  throw new Error('plan-source-note.ts returned empty stdout');
}
const parsed = JSON.parse(stdout);
if (!parsed.mutation_plan || !parsed.commit_input) {
  throw new Error('plan-source-note.ts must return mutation_plan and commit_input');
}
return [{
  json: {
    source_payload: parsed.source_payload,
    mutation_plan: parsed.mutation_plan,
    commit_input: parsed.commit_input,
    plan_b64: Buffer.from(JSON.stringify(parsed.mutation_plan), 'utf8').toString('base64'),
    commit_b64: Buffer.from(JSON.stringify(parsed.commit_input), 'utf8').toString('base64')
  }
}];

const stdout = $input.first().json.stdout ?? '';
if (!stdout.trim()) {
  throw new Error('apply-update.ts returned empty stdout');
}
return [{ json: JSON.parse(stdout) }];

const stdout = $input.first().json.stdout ?? '';
if (!stdout.trim()) {
  throw new Error('reindex.ts returned empty stdout');
}
return [{ json: JSON.parse(stdout) }];

const stdout = $input.first().json.stdout ?? '';
if (!stdout.trim()) {
  throw new Error('commit.ts returned empty stdout');
}
return [{ json: JSON.parse(stdout) }];

const sourcePayload = $node['Parse Source Payload'].json.source_payload;
const baselinePlan = $node['Parse Source Note Plan'].json.mutation_plan;
const baseUrl = (process.env.OPENROUTER_BASE_URL || 'https://openrouter.ai/api/v1').replace(/\/+$/, '');
const model = (process.env.OPENROUTER_MODEL || '').trim();
const sourceRefs = [sourcePayload.raw_path, baselinePlan.page_actions?.[0]?.path].filter(Boolean);
const requestBody = {
  ...(model ? { model } : {}),
  stream: false,
  temperature: 0,
  messages: [
    {
      role: 'system',
      content: [
        'You produce only valid JSON matching the Mutation Plan contract.',
        'This plan is for human review and must not include the baseline source-note action.',
        'Only propose small grounded changes under wiki/concepts, wiki/entities, wiki/topics, or wiki/analyses.',
        'Do not write raw content dumps. Prefer noop or empty page_actions when the source lacks reusable knowledge.',
        'Every write action must include an idempotency_key and source_refs must include the raw_path and baseline source note path when available.'
      ].join(' ')
    },
    {
      role: 'user',
      content: JSON.stringify({
        source_payload: sourcePayload,
        baseline_mutation_plan: baselinePlan,
        required_json_shape: {
          plan_id: 'plan-' + sourcePayload.source_id + '-llm-ingest-review',
          operation: 'ingest',
          summary: 'Human-review LLM plan for reusable wiki updates',
          source_refs: sourceRefs,
          page_actions: [],
          index_updates: [],
          post_actions: { reindex: true, commit: true }
        }
      }, null, 2)
    }
  ]
};
return [{
  json: {
    source_payload: sourcePayload,
    baseline_mutation_plan: baselinePlan,
    baseline_mutation_result: $node['Parse Mutation Result'].json,
    baseline_reindex_result: $node['Parse Reindex Result'].json,
    baseline_commit_result: $node['Parse Commit Result'].json,
    openrouter_url: baseUrl + '/chat/completions',
    openrouter_request: requestBody
  }
}];

function extractJson(text) {
  const stripped = text.trim().replace(/^```(?:json)?\s*/i, '').replace(/```$/i, '').trim();
  try {
    return JSON.parse(stripped);
  } catch (error) {
    const match = stripped.match(/\{[\s\S]*\}/);
    if (!match) throw error;
    return JSON.parse(match[0]);
  }
}
const raw = $input.first().json;
const response = raw.body ?? raw;
const choice = Array.isArray(response.choices) ? response.choices[0] : undefined;
const content = choice?.message?.content ?? choice?.text;
const text = Array.isArray(content)
  ? content.map((part) => typeof part === 'string' ? part : part?.text ?? '').join('').trim()
  : typeof content === 'string'
    ? content.trim()
    : '';
if (!text) {
  throw new Error('OpenRouter ingest planner response did not include JSON content');
}
const plan = extractJson(text);
if (!Array.isArray(plan.page_actions)) {
  throw new Error('LLM ingest plan must include page_actions[]');
}
if (!Array.isArray(plan.index_updates)) {
  plan.index_updates = [];
}
if (plan.page_actions.some((action) => typeof action.path === 'string' && action.path.startsWith('wiki/sources/'))) {
  throw new Error('LLM ingest plan must not duplicate the baseline wiki/sources action');
}
const packet = $node['Build OpenRouter Ingest Plan Request'].json;
return [{
  json: {
    ...packet,
    llm_mutation_plan: plan,
    llm_plan_approval_required: plan.page_actions.length > 0 || plan.index_updates.length > 0,
    openrouter_ingest_meta: {
      id: response.id ?? null,
      model: response.model ?? null,
      usage: response.usage ?? null,
      finish_reason: choice?.finish_reason ?? null
    }
  }
}];

return [{
  json: {
    status: 'baseline_ingest_applied_llm_plan_proposed',
    source_payload: $json.source_payload,
    baseline_mutation_plan: $json.baseline_mutation_plan,
    baseline_mutation_result: $json.baseline_mutation_result,
    baseline_reindex_result: $json.baseline_reindex_result,
    baseline_commit_result: $json.baseline_commit_result,
    llm_mutation_plan: $json.llm_mutation_plan,
    llm_plan_approval_required: $json.llm_plan_approval_required,
    apply_plan_command: 'node /app/dist/tools/apply-update.js --vault /data/vault --input <approved-plan.json>',
    openrouter_ingest_meta: $json.openrouter_ingest_meta
  }
}];
